## Autopilot Loop
```rust
pub struct Autopilot {
    account: AccountAutopilot,
    workload: WorkloadAutopilot,
    cost: CostAutopilot,
    config: AutopilotConfig,
}

impl Autopilot {
    pub async fn run_loop(&self) {
        let mut interval = tokio::time::interval(Duration::from_secs(60));

        loop {
            interval.tick().await;

            if !self.config.enabled {
                continue;
            }

            // Account management
            if let Ok(Some(switch)) = self.account.maybe_switch().await {
                tracing::info!("Autopilot switched account: {:?}", switch);
            }

            // Workload balancing (less frequent)
            if self.should_check_workload() {
                if let Ok(actions) = self.workload.balance_workload().await {
                    for action in actions {
                        if self.config.auto_execute_balance {
                            self.execute_balance_action(action).await;
                        }
                    }
                }
            }

            // Cost analysis (hourly)
            if self.should_check_costs() {
                if let Ok(analysis) = self.cost.analyze_costs().await {
                    if analysis.daily_cost > self.config.daily_budget {
                        self.trigger_cost_alert(analysis).await;
                    }
                }
            }
        }
    }
}
